def maybe_upgrade!(
      %Plug.Conn{
        state: :upgraded,
        adapter:
          {_, %{upgrade: {:websocket, {websock, websock_opts, connection_opts}, websocket_opts}}}
      } = conn
    ) do
  case Bandit.WebSocket.Handshake.handshake(
         %{conn | state: :unset},
         connection_opts,
         websocket_opts
       ) do
    {:ok, conn, connection_opts} ->
      {:upgrade, conn, :websocket, {websock, websock_opts, connection_opts}}

    {:error, reason} ->
      request_error!(reason)
  end
end
def maybe_upgrade!(conn) do
  {:no_upgrade, conn}
end

