def can_send?(user_id, alert_id, :reminder) do
  Repo.aggregate(
    from(dn in __MODULE__, where: dn.user_id == ^user_id and dn.alert_id == ^alert_id),
    :count
  ) == 0
end
def can_send?(user_id, alert_id, {:notification, upstream_timestamp}) do
  Repo.aggregate(
    from(dn in __MODULE__,
      where:
        dn.user_id == ^user_id and dn.alert_id == ^alert_id and
          dn.upstream_timestamp == ^upstream_timestamp and dn.type == :notification
    ),
    :count
  ) == 0
end
def can_send?(user_id, alert_id, :all_clear) do
  Repo.aggregate(
    from(dn in __MODULE__,
      where:
        dn.user_id == ^user_id and dn.alert_id == ^alert_id and
          (dn.type == :notification or dn.type == :reminder)
    ),
    :count
  ) > 0 and
    Repo.aggregate(
      from(dn in __MODULE__,
        where: dn.user_id == ^user_id and dn.alert_id == ^alert_id and dn.type == :all_clear
      ),
      :count
    ) == 0
end

def from_lines_or_routes(lines_or_routes) do
  case lines_or_routes do
    [%Route{type: :bus, short_name: name, line_id: "line-SL" <> _}] ->
      %BareLabel{label: "Silver Line #{name}"}

    [%Route{type: :bus, short_name: name}] ->
      %ModeLabel{label: name, mode: :bus}

    [%Route{type: :commuter_rail, long_name: name}] ->
      %BareLabel{label: String.replace(name, "/", " / ")}

    [%_{long_name: name, short_name: ""}] ->
      %BareLabel{label: name}

    [%_{long_name: "", short_name: name}] ->
      %BareLabel{label: name}

    [%_{long_name: name}] ->
      %BareLabel{label: name}

    _ ->
      %MultipleRoutes{}
  end
end

